operations.query:
mutation AddComment ($input: AddCommentInput!) {
	addComment(input: $input) {
		subject {
			__typename
			id
		}
		clientMutationId
	}
}

mutation AddStar ($input: AddStarInput!) {
	addStar(input: $input) {
		starrable {
			__typename
			id
			viewerHasStarred
		}
	}
}

query GetRepository ($owner: String!, $name: String!) {
	repository(owner: $owner, name: $name) {
		id
		nameWithOwner
		visibility
		url
		databaseId
		createdAt
		pushedAt
		owner {
			__typename
			... ActorFields
		}
	}
}
fragment ActorFields on Actor {
	id
	login
}

query ListPullRequests ($owner: String!, $name: String!, $includeClosed: Boolean! = false, $first: Int = 10, $after: String) {
	repository(owner: $owner, name: $name) {
		open: pullRequests(states: [OPEN], first: $first, after: $after) {
			nodes {
				id
				title
			}
			pageInfo {
				hasNextPage
				endCursor
			}
		}
		closed: pullRequests(states: [CLOSED], first: $first, after: $after) @include(if: $includeClosed) {
			nodes {
				id
				title
			}
		}
	}
}

query ListRepositoryIssues ($owner: String!, $name: String!, $first: Int = 20, $after: String) {
	repository(owner: $owner, name: $name) {
		issues(states: [OPEN], first: $first, after: $after) {
			edges {
				cursor
				node {
					... IssueFields
				}
			}
			pageInfo {
				hasNextPage
				endCursor
			}
		}
	}
}
fragment IssueFields on Issue {
	id
	title
	state
	assignees {
		__typename
		... ActorFields
	}
}
fragment ActorFields on Actor {
	id
	login
}

mutation RemoveStar ($input: RemoveStarInput!) {
	removeStar(input: $input) {
		starrable {
			__typename
			id
			viewerHasStarred
		}
	}
}
